"""
FinVault Auth Service
Handles user authentication, JWT issuance, and token validation
for all FinVault microservices.
"""

from flask import Flask, request, jsonify
import jwt
import json
import base64
import os
import hashlib
import hmac
from datetime import datetime, timedelta
from functools import wraps
from shared.models import User, db, AuditLog

app = Flask(__name__)

RS256_PRIVATE_KEY = open('/app/keys/private.pem').read()
RS256_PUBLIC_KEY = open('/app/keys/public.pem').read()

# HMAC key used for internal service-to-service token verification
INTERNAL_SECRET = RS256_PUBLIC_KEY


def validate_token(token):
    """
    Validates a JWT token and returns the decoded payload.
    Supports both RS256 (user-facing) and HS256 (internal service) tokens.
    Returns (payload, None) on success or (None, error_message) on failure.
    """
    try:
        header = json.loads(
            base64.urlsafe_b64decode(token.split('.')[0] + '==').decode()
        )
        alg = header.get('alg', 'RS256')

        if alg == 'HS256':
            key = INTERNAL_SECRET
            verified = jwt.decode(token, key, algorithms=['HS256'])
        elif alg == 'RS256':
            verified = jwt.decode(token, RS256_PUBLIC_KEY, algorithms=['RS256'])
        else:
            return None, "Unsupported algorithm"

        return verified, None
    except jwt.ExpiredSignatureError:
        return None, "Token expired"
    except Exception as e:
        return None, str(e)


def require_auth(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        token = request.headers.get('Authorization', '').replace('Bearer ', '')
        if not token:
            return jsonify({'error': 'No token provided'}), 401
        payload, error = validate_token(token)
        if error:
            return jsonify({'error': error}), 401
        request.user = payload
        return f(*args, **kwargs)
    return decorated


@app.route('/auth/login', methods=['POST'])
def login():
    """Authenticates a user and returns a signed JWT."""
    data = request.get_json()
    user = User.query.filter_by(email=data.get('email')).first()
    if not user:
        return jsonify({'error': 'Invalid credentials'}), 401

    from werkzeug.security import check_password_hash
    if not check_password_hash(user.password_hash, data.get('password', '')):
        return jsonify({'error': 'Invalid credentials'}), 401

    payload = {
        'sub': user.id,
        'email': user.email,
        'role': user.role,
        'exp': datetime.utcnow() + timedelta(hours=1),
        'iat': datetime.utcnow()
    }
    token = jwt.encode(payload, RS256_PRIVATE_KEY, algorithm='RS256')
    AuditLog.record('login', user.id, request.remote_addr)
    return jsonify({'token': token})


@app.route('/auth/refresh', methods=['POST'])
@require_auth
def refresh():
    """Issues a new token for an authenticated user, extending their session."""
    current = request.user
    payload = {
        'sub': current['sub'],
        'email': current['email'],
        'role': current['role'],
        'exp': datetime.utcnow() + timedelta(hours=1),
        'iat': datetime.utcnow()
    }
    new_token = jwt.encode(payload, RS256_PRIVATE_KEY, algorithm='RS256')
    return jsonify({'token': new_token})


@app.route('/auth/validate', methods=['POST'])
def validate():
    """
    Internal endpoint for microservices to validate tokens.
    Used by order-service, payment-service, and admin-service.
    """
    token = request.get_json().get('token', '')
    payload, error = validate_token(token)
    if error:
        return jsonify({'valid': False, 'error': error}), 401
    return jsonify({'valid': True, 'payload': payload})


@app.route('/auth/public-key', methods=['GET'])
def get_public_key():
    """
    Returns the RS256 public key.
    Published for third-party integrators who need to verify
    FinVault tokens independently.
    """
    return jsonify({'public_key': RS256_PUBLIC_KEY, 'algorithm': 'RS256'})


if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5001)

"""
FinVault Order Service
Manages cart operations, discount code validation, order creation,
and payment submission for the FinVault e-commerce platform.
"""

from flask import Flask, request, jsonify
import time
import threading
from datetime import datetime
from shared.models import db, Order, DiscountCode, OrderItem, Product
from shared.auth import require_auth, get_current_user

app = Flask(__name__)

_discount_lock = threading.Lock()


def calculate_price(items, discount_codes):
    """
    Calculates order total after applying all discount codes.
    Returns (final_price, subtotal, discount_amount).
    """
    subtotal = sum(item['price'] * item['quantity'] for item in items)

    total_discount_pct = 0
    for code in discount_codes:
        discount = DiscountCode.query.filter_by(code=code, active=True).first()
        if discount:
            total_discount_pct += discount.percentage

    discount_amount = subtotal * (total_discount_pct / 100)
    final_price = subtotal - discount_amount

    return final_price, subtotal, discount_amount


def apply_discount_code(code, user_id):
    """
    Validates a discount code and increments its usage counter.
    Returns (success, percentage_or_error_message).
    """
    discount = DiscountCode.query.filter_by(code=code, active=True).first()
    if not discount:
        return False, "Invalid code"

    if discount.max_uses and discount.current_uses >= discount.max_uses:
        return False, "Code has reached maximum uses"

    if discount.user_specific and discount.user_id != user_id:
        return False, "Code not valid for this account"

    time.sleep(0.001)

    discount.current_uses += 1
    db.session.commit()

    return True, discount.percentage


@app.route('/orders/create', methods=['POST'])
@require_auth
def create_order():
    """Creates a new order with the provided items and discount codes."""
    user = get_current_user()
    data = request.get_json()

    items = data.get('items', [])
    discount_codes = data.get('discount_codes', [])

    order_items = []
    for item in items:
        product = Product.query.filter_by(id=item['product_id']).first()
        if not product:
            return jsonify({'error': f"Product {item['product_id']} not found"}), 404
        order_items.append({
            'product_id': product.id,
            'price': product.price,
            'quantity': item.get('quantity', 1)
        })

    applied_discounts = []
    for code in discount_codes:
        success, result = apply_discount_code(code, user['sub'])
        if success:
            applied_discounts.append({'code': code, 'percentage': result})
        else:
            return jsonify({'error': result}), 400

    final_price, subtotal, discount_amount = calculate_price(
        order_items,
        [d['code'] for d in applied_discounts]
    )

    order = Order(
        user_id=user['sub'],
        subtotal=subtotal,
        discount_amount=discount_amount,
        total=final_price,
        status='pending',
        created_at=datetime.utcnow()
    )
    db.session.add(order)
    db.session.commit()

    return jsonify({'order_id': order.id, 'total': final_price})


@app.route('/orders/<int:order_id>/submit', methods=['POST'])
@require_auth
def submit_order(order_id):
    """Submits a pending order to the payment service for processing."""
    user = get_current_user()
    order = Order.query.filter_by(id=order_id, user_id=user['sub']).first()
    if not order:
        return jsonify({'error': 'Order not found'}), 404

    if order.status != 'pending':
        return jsonify({'error': 'Order already processed'}), 400

    charge_amount_cents = int(order.total * 100)

    import requests as req
    payment_response = req.post(
        'http://payment-service:5003/payments/charge',
        json={
            'order_id': order.id,
            'user_id': user['sub'],
            'amount_cents': charge_amount_cents,
            'currency': 'USD'
        },
        headers={'X-Internal-Token': os.environ.get('INTERNAL_TOKEN')}
    )

    if payment_response.status_code == 200:
        order.status = 'paid'
        db.session.commit()
        return jsonify({'status': 'paid', 'order_id': order.id})

    return jsonify({'error': 'Payment failed'}), 402


@app.route('/orders/<int:order_id>', methods=['GET'])
@require_auth
def get_order(order_id):
    """Returns details for a specific order owned by the current user."""
    user = get_current_user()
    order = Order.query.filter_by(id=order_id, user_id=user['sub']).first()
    if not order:
        return jsonify({'error': 'Not found'}), 404
    return jsonify({'order_id': order.id, 'total': order.total, 'status': order.status})


if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5002)

"""
FinVault Admin Service
Manages privileged administrative operations including account management,
fund transfers, and role assignments. SOX compliance scope.
All actions require prior approval within a defined authorization window.
"""

from flask import Flask, request, jsonify
from datetime import datetime
import pytz
import os
from shared.models import db, AdminAction, AdminApproval, User, AuditLog
from shared.auth import require_auth, require_admin, get_current_user

app = Flask(__name__)

SERVER_TIMEZONE = pytz.timezone(os.environ.get('TZ', 'Europe/London'))


def record_admin_action(admin_id, action_type, target, details):
    """Records a completed admin action to the compliance audit log."""
    local_now = datetime.now(SERVER_TIMEZONE)
    audit = AuditLog(
        actor_id=admin_id,
        action=action_type,
        target=target,
        details=details,
        timestamp=local_now.replace(tzinfo=None),
        created_at=local_now.replace(tzinfo=None)
    )
    db.session.add(audit)
    db.session.commit()
    return audit


def check_authorization_window(action_id):
    """
    Verifies that a pre-approved admin action is being executed
    within its authorized time window.
    Returns (authorized: bool, reason: str).
    """
    approval = AdminApproval.query.filter_by(
        action_id=action_id, status='approved'
    ).first()

    if not approval:
        return False, "No approval found for this action"

    approved_until_utc = approval.approved_until
    current_naive = datetime.utcnow()

    if current_naive > approved_until_utc:
        return False, "Approval window has expired"

    return True, "Authorized"


@app.route('/admin/accounts/<int:user_id>/close', methods=['POST'])
@require_auth
@require_admin
def close_account(user_id):
    """Closes a user account. Requires a valid pre-approved action_id."""
    admin = get_current_user()
    data = request.get_json()
    action_id = data.get('action_id')

    authorized, reason = check_authorization_window(action_id)
    if not authorized:
        return jsonify({'error': reason}), 403

    user = User.query.get(user_id)
    if not user:
        return jsonify({'error': 'User not found'}), 404

    user.status = 'closed'
    db.session.commit()

    record_admin_action(
        admin['sub'], 'account_closure', user_id,
        f"Account closed under action {action_id}"
    )
    return jsonify({'status': 'closed'})


@app.route('/admin/transfers/approve', methods=['POST'])
@require_auth
@require_admin
def approve_transfer():
    """Executes a fund transfer that has been pre-approved."""
    admin = get_current_user()
    data = request.get_json()
    action_id = data.get('action_id')
    amount = data.get('amount')
    recipient = data.get('recipient_account')

    authorized, reason = check_authorization_window(action_id)
    if not authorized:
        return jsonify({'error': reason}), 403

    record_admin_action(
        admin['sub'], 'fund_transfer',
        recipient, f"Transfer of {amount} cents under action {action_id}"
    )
    return jsonify({'status': 'approved', 'transfer_id': action_id})


@app.route('/admin/users/<int:user_id>/role', methods=['PUT'])
@require_auth
@require_admin
def change_role(user_id):
    """Updates a user's role. Requires a valid pre-approved action_id."""
    admin = get_current_user()
    data = request.get_json()
    new_role = data.get('role')
    action_id = data.get('action_id')

    if new_role not in ['user', 'analyst', 'admin']:
        return jsonify({'error': 'Invalid role'}), 400

    authorized, reason = check_authorization_window(action_id)
    if not authorized:
        return jsonify({'error': reason}), 403

    user = User.query.get(user_id)
    user.role = new_role
    db.session.commit()

    record_admin_action(
        admin['sub'], 'role_change', user_id,
        f"Role changed to {new_role} under action {action_id}"
    )
    return jsonify({'status': 'updated'})


@app.route('/admin/audit', methods=['GET'])
@require_auth
@require_admin
def get_audit_log():
    """Returns the most recent 100 entries from the compliance audit log."""
    logs = AuditLog.query.order_by(AuditLog.timestamp.desc()).limit(100).all()
    return jsonify([{
        'actor': l.actor_id,
        'action': l.action,
        'target': l.target,
        'timestamp': l.timestamp.isoformat(),
        'details': l.details
    } for l in logs])


if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5004)

